import functools, random, subprocess, sys


def brute(a, l, r):
    vals = a[l:r + 1]
    m = len(vals)

    @functools.lru_cache(None)
    def dp(mask):
        if not mask:
            return 0
        first_bit = mask & -mask
        i = first_bit.bit_length() - 1
        rest = mask ^ first_bit
        best = dp(rest)
        choices = rest
        while choices:
            bit = choices & -choices
            j = bit.bit_length() - 1
            choices ^= bit
            if 2 * min(vals[i], vals[j]) <= max(vals[i], vals[j]):
                best = max(best, 1 + dp(rest ^ bit))
        return best

    return dp((1 << m) - 1)

